import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppScreen {
  SPLASH = 'SPLASH',
  DASHBOARD = 'DASHBOARD',
  CAMERA = 'CAMERA',
  ANALYSIS = 'ANALYSIS',
  PROFILE = 'PROFILE',
  STATS = 'STATS',
  PLANS = 'PLANS'
}

export interface Ingredient {
  name: string;
  serving: string;
  calories: number;
  match: number;
}

export interface MealAnalysis {
  name: string;
  totalCalories: number;
  protein: number;
  carbs: number;
  fats: number;
  ingredients: Ingredient[];
  imageUrl?: string;
}

export interface MealHistoryItem {
  id: string;
  name: string;
  calories: number;
  time: string;
  image: string;
  status: 'AI RECOGNIZED' | 'VERIFIED';
}

import { GoogleGenAI, Type } from "@google/genai";
import { MealAnalysis } from "../types";

export const analyzeFoodImage = async (base64Image: string): Promise<MealAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image,
          },
        },
        {
          text: "Analyze this food image. Identify the dish and its ingredients. Provide estimated calories, protein (g), carbs (g), and fats (g). Return the data in JSON format."
        }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING, description: "Name of the dish" },
          totalCalories: { type: Type.NUMBER },
          protein: { type: Type.NUMBER },
          carbs: { type: Type.NUMBER },
          fats: { type: Type.NUMBER },
          ingredients: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                serving: { type: Type.STRING },
                calories: { type: Type.NUMBER },
                match: { type: Type.NUMBER, description: "Confidence percentage (0-100)" }
              },
              required: ["name", "serving", "calories", "match"]
            }
          }
        },
        required: ["name", "totalCalories", "protein", "carbs", "fats", "ingredients"]
      }
    }
  });

  const analysis = JSON.parse(response.text || '{}') as MealAnalysis;
  return analysis;
};

