import React, { useRef, useState, useEffect, useCallback } from 'react';
import { analyzeFoodImage } from '../services/geminiService';
import { MealAnalysis } from '../types';

interface CameraScreenProps {
  onBack: () => void;
  onResult: (result: MealAnalysis) => void;
}

const CameraScreen: React.FC<CameraScreenProps> = ({ onBack, onResult }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [mode, setMode] = useState<'single' | 'multi'>('single');

  const startCamera = useCallback(async () => {
    try {
      const constraints = {
        video: { facingMode: 'environment' },
        audio: false
      };
      const newStream = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(newStream);
      if (videoRef.current) {
        videoRef.current.srcObject = newStream;
      }
    } catch (err) {
      console.error("Error accessing camera:", err);
    }
  }, []);

  useEffect(() => {
    startCamera();
    return () => {
      stream?.getTracks().forEach(track => track.stop());
    };
  }, [startCamera]);

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isAnalyzing) return;

    setIsAnalyzing(true);
    const context = canvasRef.current.getContext('2d');
    if (context) {
      canvasRef.current.width = videoRef.current.videoWidth;
      canvasRef.current.height = videoRef.current.videoHeight;
      context.drawImage(videoRef.current, 0, 0);

      const base64Image = canvasRef.current.toDataURL('image/jpeg', 0.8).split(',')[1];
      try {
        const result = await analyzeFoodImage(base64Image);
        onResult({ ...result, imageUrl: canvasRef.current.toDataURL('image/jpeg') });
      } catch (err) {
        console.error("Analysis failed:", err);
        alert("Could not identify food. Please try again.");
      } finally {
        setIsAnalyzing(false);
      }
    }
  };

  return (
    <div className="relative flex h-screen w-full flex-col overflow-hidden bg-black">
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        className="absolute inset-0 w-full h-full object-cover z-0"
      />
      <canvas ref={canvasRef} className="hidden" />

      {/* Top UI */}
      <div className="relative z-30 flex items-center p-4 pt-12 justify-between">
        <button 
          onClick={onBack}
          className="flex size-10 items-center justify-center rounded-full bg-black/40 backdrop-blur-md"
        >
          <span className="material-symbols-outlined text-white">close</span>
        </button>
        <div className="flex flex-col items-center">
          <h2 className="text-white text-sm font-bold leading-tight tracking-wider uppercase">AI Recognition</h2>
          <div className="flex items-center gap-1">
            <div className="size-2 rounded-full bg-primary animate-pulse"></div>
            <span className="text-xs text-white/80 font-medium">Live Analysis</span>
          </div>
        </div>
        <button className="flex size-10 items-center justify-center rounded-full bg-black/40 backdrop-blur-md">
          <span className="material-symbols-outlined text-white">help</span>
        </button>
      </div>

      {/* Viewfinder Overlay */}
      <div className="relative z-10 flex-1 flex items-center justify-center p-8">
        <div className="relative w-full aspect-square max-w-[320px]">
          <div className="absolute top-0 left-0 w-10 h-10 border-t-4 border-l-4 border-primary rounded-tl-xl"></div>
          <div className="absolute top-0 right-0 w-10 h-10 border-t-4 border-r-4 border-primary rounded-tr-xl"></div>
          <div className="absolute bottom-0 left-0 w-10 h-10 border-b-4 border-l-4 border-primary rounded-bl-xl"></div>
          <div className="absolute bottom-0 right-0 w-10 h-10 border-b-4 border-r-4 border-primary rounded-br-xl"></div>
          <div className="absolute top-[40%] left-0 w-full h-[2px] bg-gradient-to-r from-transparent via-primary to-transparent shadow-[0_0_15px_#13ec5b] animate-bounce"></div>

          {isAnalyzing && (
            <div className="absolute inset-0 flex items-center justify-center bg-black/40 rounded-xl">
              <div className="flex flex-col items-center gap-2">
                <div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
                <span className="text-xs font-bold text-primary">ANALYZING...</span>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Bottom Controls */}
      <div className="relative z-30 bg-gradient-to-t from-black/80 via-black/40 to-transparent pb-10 pt-6 px-4">
        <h4 className="text-white text-sm font-medium leading-normal tracking-wide text-center mb-4 opacity-90">
          Point camera at your meal
        </h4>

        <div className="flex max-w-[280px] mx-auto mb-8">
          <div className="flex h-11 flex-1 items-center justify-center rounded-full bg-black/60 backdrop-blur-xl p-1 border border-white/10">
            <button 
              onClick={() => setMode('single')}
              className={`flex-1 h-full rounded-full text-sm font-bold transition-all ${mode === 'single' ? 'bg-primary text-black' : 'text-white/70'}`}
            >
              Single Item
            </button>
            <button 
              onClick={() => setMode('multi')}
              className={`flex-1 h-full rounded-full text-sm font-bold transition-all ${mode === 'multi' ? 'bg-primary text-black' : 'text-white/70'}`}
            >
              Multi-item
            </button>
          </div>
        </div>

        <div className="flex items-center justify-between max-w-xs mx-auto mb-4">
          <button className="flex shrink-0 items-center justify-center rounded-xl size-12 bg-black/40 border border-white/20 overflow-hidden">
            <img src="https://picsum.photos/100" className="w-full h-full object-cover" alt="Gallery" />
          </button>

          <div className="relative flex items-center justify-center">
            <div className={`absolute inset-0 rounded-full border-2 border-primary ${isAnalyzing ? '' : 'animate-ping opacity-20'}`}></div>
            <button 
              onClick={captureAndAnalyze}
              disabled={isAnalyzing}
              className="relative flex shrink-0 items-center justify-center rounded-full size-20 bg-white p-1"
            >
              <div className="w-full h-full rounded-full border-4 border-black/10 flex items-center justify-center">
                {isAnalyzing ? (
                   <div className="size-6 bg-red-500 rounded-sm"></div>
                ) : (
                  <div className="size-16 rounded-full border-2 border-black/5 flex items-center justify-center">
                    <div className="size-14 rounded-full bg-slate-100"></div>
                  </div>
                )}
              </div>
            </button>
          </div>

          <button className="flex shrink-0 items-center justify-center rounded-full size-12 bg-black/40 backdrop-blur-md text-white border border-white/10">
            <span className="material-symbols-outlined text-2xl">flash_on</span>
          </button>
        </div>

        <p className="text-center text-[10px] text-white/40 uppercase tracking-[0.2em] font-bold">
          Tap to capture & log
        </p>
      </div>

      <div className="relative z-30 flex justify-center pb-2">
        <div className="w-32 h-1.5 bg-white/30 rounded-full"></div>
      </div>
    </div>
  );
};

export default CameraScreen;

import React from 'react';
