        />
      </nav>

      <div className="bg-background-dark h-4 w-full"></div>
    </div>
  );
};

const NavItem = ({ icon, label, active, onClick }: any) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center gap-1 ${active ? 'text-primary' : 'text-[#92c9a4]'}`}
  >
    <span className="material-symbols-outlined text-[26px]" style={{ fontVariationSettings: `'FILL' ${active ? 1 : 0}` }}>{icon}</span>
    <span className="text-[10px] font-medium">{label}</span>
  </button>
);

export default Navbar;

