        return (
          <CameraScreen 
            onBack={() => setCurrentScreen(AppScreen.DASHBOARD)} 
            onResult={handleAnalysisComplete} 
          />
        );
      case AppScreen.ANALYSIS:
        return analysisResult ? (
          <AnalysisResults 
            result={analysisResult} 
            onSave={handleSaveMeal} 
            onBack={() => setCurrentScreen(AppScreen.CAMERA)} 
          />
        ) : null;
      case AppScreen.PROFILE:
        return <ProfileScreen onBack={() => setCurrentScreen(AppScreen.DASHBOARD)} />;
      case AppScreen.STATS:
        return <StatsScreen onBack={() => setCurrentScreen(AppScreen.DASHBOARD)} />;
      case AppScreen.PLANS:
        return <PlansScreen currentPlan={activePlan} onSelectPlan={setActivePlan} />;
      default:
        return <Dashboard history={mealHistory} onOpenProfile={() => setCurrentScreen(AppScreen.PROFILE)} />;
    }
  };

  const showNavbar = [AppScreen.DASHBOARD, AppScreen.PROFILE, AppScreen.STATS, AppScreen.PLANS].includes(currentScreen);

  return (
    <div className="h-screen w-full relative flex flex-col bg-background-dark overflow-hidden">
      <div className="flex-1 overflow-y-auto no-scrollbar relative">
        {renderScreen()}
      </div>
      {showNavbar && (
        <Navbar 
          activeScreen={currentScreen} 
          onNavigate={setCurrentScreen} 
          onScan={handleOpenCamera} 
        />
      )}
    </div>
  );
};

