const App: React.FC = () => {
  const [currentScreen, setCurrentScreen] = useState<AppScreen>(AppScreen.SPLASH);
  const [analysisResult, setAnalysisResult] = useState<MealAnalysis | null>(null);

  // Default user profile
  const [userProfile, setUserProfile] = useState<UserProfile>({
    weight: 78,
    height: 175,
    age: 28,
    gender: 'male',
    activityLevel: 1.2
  });

  const [activePlanId, setActivePlanId] = useState<string>('weight-loss');

  const availablePlans: MealPlan[] = [
    {
      id: 'weight-loss',
      title: 'Weight Loss',
      desc: 'Targeted calorie deficit for healthy fat loss.',
      kcalModifier: -500,
      proteinPct: 35,
      carbsPct: 35,
      fatsPct: 30,
      image: 'https://images.unsplash.com/photo-1490645935967-10de6ba17061?q=80&w=400&auto=format&fit=crop'
    },
    {
      id: 'muscle-building',
      title: 'Muscle Building',
      desc: 'High protein focus for lean muscle gains.',
      kcalModifier: 500,
      proteinPct: 40,
      carbsPct: 40,
      fatsPct: 20,
      image: 'https://images.unsplash.com/photo-1532384748853-8f54a8f476e2?q=80&w=400&auto=format&fit=crop'
    },
    {
      id: 'keto-diet',
      title: 'Keto Diet',
      desc: 'Low carb, high fat for metabolic efficiency.',
      kcalModifier: -200,
      proteinPct: 20,
      carbsPct: 5,
      fatsPct: 75,
      image: 'https://images.unsplash.com/photo-1512621776951-a57141f2eefd?q=80&w=400&auto=format&fit=crop'
    },
    {
      id: 'mediterranean',
      title: 'Mediterranean',
      desc: 'Heart-healthy fats and fresh whole foods.',
      kcalModifier: 0,
      proteinPct: 25,
      carbsPct: 45,
      fatsPct: 30,
      image: 'https://images.unsplash.com/photo-1490645935967-10de6ba17061?q=80&w=400&auto=format&fit=crop'
    }
  ];

  // Dynamic calculation logic
  const tdee = useMemo(() => {
    const { weight, height, age, gender, activityLevel } = userProfile;
    const bmr = gender === 'male'
      ? (10 * weight) + (6.25 * height) - (5 * age) + 5
      : (10 * weight) + (6.25 * height) - (5 * age) - 161;
    return Math.round(bmr * activityLevel);
  }, [userProfile]);

  const activePlan = useMemo(() => {
    const plan = availablePlans.find(p => p.id === activePlanId) || availablePlans[0];
    return {
      ...plan,
      dynamicKcal: tdee + plan.kcalModifier
    };
  }, [activePlanId, tdee]);

  const [mealHistory, setMealHistory] = useState<MealHistoryItem[]>([
    {
      id: '1',
      name: 'Avocado Toast',
      calories: 340,
      time: '8:30 AM',
      image: 'https://lh3.googleusercontent.com/aida-public/AB6AXuAgHYXIKTK1Y1dqYvv3c1HhNY3Bo-rNWwfAENjPb75BYK4NUYtDQJWEM1eaLmw1dUvjQYSLKtfpcrsvvfhD_K32R0rS7iX10wWHdOuRRBad9rAyi3bA1xgMjcI5mou5K9OPinF8naHVX8caqHyvHN6qHgpi_ziXBnd8qMzZDkBuv5pm0qYbK8vm6uz19YsqDFCpWyfugeWI6-H4IuM1_WJRzEb6tvH4DAgDxEvtNQwCYwjRX-wCx32c2x3diXxjlot2lQ3Z6a43SA',
      status: 'AI RECOGNIZED'
    }
  ]);

  const handleStart = () => setCurrentScreen(AppScreen.DASHBOARD);
  const handleOpenCamera = () => setCurrentScreen(AppScreen.CAMERA);
  const handleAnalysisComplete = (result: MealAnalysis) => {
    setAnalysisResult(result);
    setCurrentScreen(AppScreen.ANALYSIS);
  };
  const handleSaveMeal = (meal: MealAnalysis) => {
    const newItem: MealHistoryItem = {
      id: Date.now().toString(),
      name: meal.name,
      calories: meal.totalCalories,
      time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      image: meal.imageUrl || 'https://picsum.photos/200',
      status: 'VERIFIED'
    };
    setMealHistory(prev => [newItem, ...prev]);
    setCurrentScreen(AppScreen.DASHBOARD);
  };

  const renderScreen = () => {
    switch (currentScreen) {
      case AppScreen.SPLASH:
        return <SplashScreen onStart={handleStart} />;
      case AppScreen.DASHBOARD:
        return <Dashboard history={mealHistory} onOpenProfile={() => setCurrentScreen(AppScreen.PROFILE)} targetKcal={activePlan.dynamicKcal || 2000} />;
      case AppScreen.CAMERA:
        return <CameraScreen onBack={() => setCurrentScreen(AppScreen.DASHBOARD)} onResult={handleAnalysisComplete} />;
      case AppScreen.ANALYSIS:
        return analysisResult ? <AnalysisResults result={analysisResult} onSave={handleSaveMeal} onBack={() => setCurrentScreen(AppScreen.CAMERA)} /> : null;
      case AppScreen.PROFILE:
        return <ProfileScreen profile={userProfile} onUpdateProfile={setUserProfile} onBack={() => setCurrentScreen(AppScreen.DASHBOARD)} tdee={tdee} />;
      case AppScreen.STATS:
        return <StatsScreen onBack={() => setCurrentScreen(AppScreen.DASHBOARD)} />;
      case AppScreen.PLANS:
        return <PlansScreen currentPlan={activePlan} availablePlans={availablePlans} tdee={tdee} onSelectPlanId={setActivePlanId} />;
      default:
        return <Dashboard history={mealHistory} onOpenProfile={() => setCurrentScreen(AppScreen.PROFILE)} targetKcal={2000} />;
    }
  };

  const showNavbar = [AppScreen.DASHBOARD, AppScreen.PROFILE, AppScreen.STATS, AppScreen.PLANS].includes(currentScreen);

  return (
    <div className="h-screen w-full relative flex flex-col bg-background-dark overflow-hidden">
      <div className="flex-1 overflow-y-auto no-scrollbar relative">
        {renderScreen()}
      </div>
      {showNavbar && (
        <Navbar activeScreen={currentScreen} onNavigate={setCurrentScreen} onScan={handleOpenCamera} />
      )}
    </div>
  );
};

