    if (!stream) return;
    const track = stream.getVideoTracks()[0];
    if (track) {
      try {
        const newFlashState = !flashOn;
        await track.applyConstraints({
          advanced: [{ torch: newFlashState }]
        } as any);
        setFlashOn(newFlashState);
      } catch (err) {
        console.error("Error toggling flash:", err);
      }
