import React, { useState } from 'react';
import { UserProfile } from '../types';

interface SettingsScreenProps {
  settings: {
    language: string;
    units: string;
    notifications: boolean;
  };
  onUpdateSettings: (s: any) => void;
  onBack: () => void;
  onSignOut: () => void;
  onClearData: () => void;
  userProfile: UserProfile;
}

const SettingsScreen: React.FC<SettingsScreenProps> = ({ settings, onUpdateSettings, onBack, onSignOut, onClearData, userProfile }) => {
  const [activeModal, setActiveModal] = useState<'language' | 'units' | 'account' | 'privacy' | 'tos' | null>(null);
  const [toast, setToast] = useState<string | null>(null);

  const showToast = (msg: string) => {
    setToast(msg);
    setTimeout(() => setToast(null), 2500);
  };

  const toggleNotifications = () => {
    onUpdateSettings({ ...settings, notifications: !settings.notifications });
    showToast(`Notifications ${!settings.notifications ? 'enabled' : 'disabled'}`);
  };

  const updateLanguage = (lang: string) => {
    onUpdateSettings({ ...settings, language: lang });
    setActiveModal(null);
    showToast(`Language set to ${lang}`);
  };

  const updateUnits = (unit: string) => {
    onUpdateSettings({ ...settings, units: unit });
    setActiveModal(null);
    showToast(`Measurement units set to ${unit}`);
  };

  const handleClearCache = () => {
    if (confirm("Are you sure you want to clear all your meal history and app data? This cannot be undone.")) {
      onClearData();
      showToast("App data cleared successfully");
    }
  };

  const renderModal = () => {
    if (!activeModal) return null;

    const ModalOverlay = ({ children, title }: { children: React.ReactNode, title: string }) => (
      <div className="fixed inset-0 z-[100] flex items-end justify-center bg-black/80 backdrop-blur-sm px-4 pb-8 transition-all animate-in fade-in duration-300">
        <div className="w-full max-w-md bg-zinc-900 rounded-3xl overflow-hidden shadow-2xl animate-in slide-in-from-bottom-20 duration-500 border border-white/10">
          <div className="flex items-center justify-between p-6 border-b border-white/5">
            <h3 className="text-xl font-bold">{title}</h3>
            <button onClick={() => setActiveModal(null)} className="size-10 flex items-center justify-center rounded-full bg-white/5">
              <span className="material-symbols-outlined">close</span>
            </button>
          </div>
          <div className="p-6">
            {children}
          </div>
        </div>
      </div>
    );

    switch (activeModal) {
      case 'language':
        return (
          <ModalOverlay title="Select Language">
            <div className="space-y-3">
              {['English', 'Chinese', 'Spanish', 'French', 'German'].map(lang => (
                <button 
                  key={lang} 
                  onClick={() => updateLanguage(lang)}
                  className={`w-full flex items-center justify-between p-4 rounded-xl border transition-all ${settings.language === lang ? 'bg-primary/10 border-primary text-primary' : 'bg-white/5 border-transparent text-white'}`}
                >
                  <span className="font-bold">{lang}</span>
                  {settings.language === lang && <span className="material-symbols-outlined">check_circle</span>}
                </button>
              ))}
            </div>
          </ModalOverlay>
        );
      case 'units':
        return (
          <ModalOverlay title="Measurement Units">
            <div className="space-y-3">
              {['Metric (kg, cm)', 'Imperial (lbs, ft)'].map(unit => (
                <button 
                  key={unit} 
                  onClick={() => updateUnits(unit)}
                  className={`w-full flex items-center justify-between p-4 rounded-xl border transition-all ${settings.units === unit ? 'bg-primary/10 border-primary text-primary' : 'bg-white/5 border-transparent text-white'}`}
                >
                  <span className="font-bold">{unit}</span>
                  {settings.units === unit && <span className="material-symbols-outlined">check_circle</span>}
                </button>
              ))}
            </div>
          </ModalOverlay>
        );
      case 'account':
        return (
          <ModalOverlay title="Account Details">
            <div className="space-y-6">
              <div className="flex items-center gap-4 p-4 bg-white/5 rounded-2xl">
                <div className="size-16 rounded-full bg-cover bg-center" style={{ backgroundImage: `url(${userProfile.avatar})` }} />
                <div>
                  <p className="text-lg font-bold">{userProfile.name}</p>
                  <p className="text-sm text-slate-400">Premium Member</p>
                </div>
              </div>
              <div className="space-y-4">
                <InfoRow label="Email" value="alex.rivera@example.com" />
                <InfoRow label="Member Since" value="January 2024" />
                <InfoRow label="Data Usage" value="12.4 MB" />
              </div>
              <button onClick={() => setActiveModal(null)} className="w-full py-4 bg-primary text-black font-bold rounded-xl">Done</button>
            </div>
          </ModalOverlay>
        );
      case 'privacy':
        return (
          <ModalOverlay title="Privacy Settings">
            <div className="space-y-4">
              <ToggleRow label="Share Progress Anonymously" active={true} />
              <ToggleRow label="Enable Analytics" active={false} />
              <ToggleRow label="Targeted Nutritional Tips" active={true} />
              <div className="pt-4">
                <p className="text-xs text-slate-500 leading-relaxed">
                  We take your data seriously. All meal images are processed securely and ingredients are mapped using private AI models.
                </p>
              </div>
            </div>
          </ModalOverlay>
        );
      default:
        return null;
    }
  };

  return (
    <div className="bg-background-dark min-h-screen text-white pb-32 max-w-md mx-auto flex flex-col relative">
      {renderModal()}

      {/* Toast Notification */}
      {toast && (
        <div className="fixed top-20 left-1/2 -translate-x-1/2 z-[110] bg-primary text-black px-6 py-3 rounded-full font-bold shadow-2xl flex items-center gap-2 animate-in slide-in-from-top-10 duration-300">
          <span className="material-symbols-outlined text-xl">info</span>
