        </div>
      )}

      <header className="flex items-center p-4 pt-6 sticky top-0 bg-background-dark/80 backdrop-blur-md z-10 border-b border-white/5">
        <button onClick={onBack} className="flex size-10 items-center justify-start">
          <span className="material-symbols-outlined text-2xl">arrow_back_ios</span>
        </button>
        <h2 className="text-lg font-bold leading-tight tracking-tight flex-1 text-center">Settings</h2>
        <div className="w-10"></div>
      </header>

      <div className="px-4 py-6 space-y-8">
        {/* General Section */}
        <section>
          <h3 className="text-xs font-bold text-primary uppercase tracking-[0.2em] mb-4 px-2">General</h3>
          <div className="bg-[#193322]/40 rounded-2xl border border-white/5 overflow-hidden shadow-inner">
            <SettingsItem 
              icon="language" 
