        {/* Account Section */}
        <section>
          <h3 className="text-xs font-bold text-primary uppercase tracking-[0.2em] mb-4 px-2">Account</h3>
          <div className="bg-[#193322]/40 rounded-2xl border border-white/5 overflow-hidden shadow-inner">
            <SettingsItem icon="person_outline" label="Account Details" onClick={() => setActiveModal('account')} />
            <SettingsItem icon="lock_outline" label="Privacy & Security" onClick={() => setActiveModal('privacy')} />
            <SettingsItem icon="cloud_sync" label="Cloud Backup" value="Active" onClick={() => showToast("Syncing with cloud...")} />
          </div>
        </section>

        {/* About Section */}
        <section>
          <h3 className="text-xs font-bold text-primary uppercase tracking-[0.2em] mb-4 px-2">App Info</h3>
          <div className="bg-[#193322]/40 rounded-2xl border border-white/5 overflow-hidden shadow-inner">
            <div className="flex items-center justify-between p-4 border-b border-white/5">
              <div className="flex items-center gap-3">
                <span className="material-symbols-outlined text-slate-400">info</span>
