            </div>
            <SettingsItem icon="description" label="Terms of Service" onClick={() => showToast("Opening Terms...")} />
            <SettingsItem icon="verified_user" label="Privacy Policy" onClick={() => showToast("Opening Policy...")} />
            <button 
              onClick={handleClearCache}
              className="w-full text-left flex items-center gap-3 p-4 text-accent-orange hover:bg-accent-orange/10 transition-colors"
            >
              <span className="material-symbols-outlined">delete_forever</span>
              <span className="font-bold uppercase tracking-widest text-xs">Clear App Data</span>
            </button>
          </div>
        </section>

        <button 
          onClick={() => {
            if(confirm("Sign out of CalorieAI?")) onSignOut();
          }}
          className="w-full py-4 rounded-2xl bg-white/5 text-slate-300 font-bold border border-white/5 hover:bg-red-500/10 hover:border-red-500/20 hover:text-red-400 active:scale-95 transition-all uppercase tracking-widest text-sm"
        >
          Sign Out
        </button>
      </div>

      <div className="flex flex-col items-center py-8 opacity-20 mt-auto">
