          <span className="material-symbols-outlined text-primary">analytics</span>
        </div>
        <p className="text-[10px] font-black uppercase tracking-[0.5em] text-primary">CalorieAI Premium</p>
        <p className="text-[8px] mt-1">MADE WITH ❤️ IN CALIFORNIA</p>
      </div>
    </div>
  );
};

const SettingsItem = ({ icon, label, value, onClick }: any) => (
  <button 
    onClick={onClick}
    className="w-full flex items-center justify-between p-4 hover:bg-white/5 border-b border-white/5 last:border-0 transition-colors"
