const App: React.FC = () => {
  const [currentScreen, setCurrentScreen] = useState<AppScreen>(AppScreen.SPLASH);
  const [analysisResult, setAnalysisResult] = useState<MealAnalysis | null>(null);

  const [settings, setSettings] = useState({
    language: 'English',
    units: 'Metric',
    notifications: true
  });

  const t = useMemo(() => translations[settings.language] || translations.English, [settings.language]);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Alex Rivera',
    avatar: 'https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?q=80&w=200&auto=format&fit=crop',
    weight: 78, // stored in kg
    height: 175, // stored in cm
    age: 28,
    gender: 'male',
    activityLevel: 1.2
  });

  const [activePlanId, setActivePlanId] = useState<string>('weight-loss');

  const availablePlans: MealPlan[] = [
    {
      id: 'weight-loss',
      title: 'Weight Loss',
      desc: 'Targeted calorie deficit for healthy fat loss.',
      kcalModifier: -500,
      proteinPct: 35,
      carbsPct: 35,
      fatsPct: 30,
      image: 'https://images.unsplash.com/photo-1490645935967-10de6ba17061?q=80&w=400&auto=format&fit=crop'
    },
    {
      id: 'muscle-building',
      title: 'Muscle Building',
      desc: 'High protein focus for lean muscle gains.',
      kcalModifier: 500,
      proteinPct: 40,
      carbsPct: 40,
      fatsPct: 20,
      image: 'https://images.unsplash.com/photo-1532384748853-8f54a8f476e2?q=80&w=400&auto=format&fit=crop'
    }
  ];

  const tdee = useMemo(() => {
    const { weight, height, age, gender, activityLevel } = userProfile;
    const bmr = gender === 'male'
      ? (10 * weight) + (6.25 * height) - (5 * age) + 5
      : (10 * weight) + (6.25 * height) - (5 * age) - 161;
    return Math.round(bmr * activityLevel);
  }, [userProfile]);

  const activePlan = useMemo(() => {
    const plan = availablePlans.find(p => p.id === activePlanId) || availablePlans[0];
    return {
      ...plan,
      dynamicKcal: tdee + plan.kcalModifier
    };
  }, [activePlanId, tdee]);

  const [mealHistory, setMealHistory] = useState<MealHistoryItem[]>([
    {
      id: '1',
      name: 'Avocado Toast',
      calories: 340,
      time: '8:30 AM',
      image: 'https://lh3.googleusercontent.com/aida-public/AB6AXuAgHYXIKTK1Y1dqYvv3c1HhNY3Bo-rNWwfAENjPb75BYK4NUYtDQJWEM1eaLmw1dUvjQYSLKtfpcrsvvfhD_K32R0rS7iX10wWHdOuRRBad9rAyi3bA1xgMjcI5mou5K9OPinF8naHVX8caqHyvHN6qHgpi_ziXBnd8qMzZDkBuv5pm0qYbK8vm6uz19YsqDFCpWyfugeWI6-H4IuM1_WJRzEb6tvH4DAgDxEvtNQwCYwjRX-wCx32c2x3diXxjlot2lQ3Z6a43SA',
      status: 'AI RECOGNIZED'
    }
  ]);

  const handleStart = () => setCurrentScreen(AppScreen.DASHBOARD);
  const handleOpenCamera = () => setCurrentScreen(AppScreen.CAMERA);

  const handleSignOut = () => setCurrentScreen(AppScreen.SPLASH);
  const handleClearData = () => setMealHistory([]);

  const renderScreen = () => {
    const commonProps = { t, settings };
    switch (currentScreen) {
      case AppScreen.SPLASH:
        return <SplashScreen onStart={handleStart} />;
      case AppScreen.DASHBOARD:
        return <Dashboard {...commonProps} history={mealHistory} profile={userProfile} onOpenProfile={() => setCurrentScreen(AppScreen.PROFILE)} targetKcal={activePlan.dynamicKcal || 2000} />;
      case AppScreen.CAMERA:
        return <CameraScreen onBack={() => setCurrentScreen(AppScreen.DASHBOARD)} onResult={(r) => { setAnalysisResult(r); setCurrentScreen(AppScreen.ANALYSIS); }} />;
      case AppScreen.ANALYSIS:
        return analysisResult ? <AnalysisResults result={analysisResult} onSave={(m) => {
          const newItem: MealHistoryItem = {
            id: Date.now().toString(),
            name: m.name,
            calories: m.totalCalories,
            time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            image: m.imageUrl || 'https://picsum.photos/200',
            status: 'VERIFIED'
          };
          setMealHistory(prev => [newItem, ...prev]);
          setCurrentScreen(AppScreen.DASHBOARD);
        }} onBack={() => setCurrentScreen(AppScreen.CAMERA)} /> : null;
      case AppScreen.PROFILE:
        return <ProfileScreen 
          {...commonProps}
          profile={userProfile} 
          onUpdateProfile={setUserProfile} 
          onBack={() => setCurrentScreen(AppScreen.DASHBOARD)} 
          onOpenSettings={() => setCurrentScreen(AppScreen.SETTINGS)}
          tdee={tdee} 
        />;
      case AppScreen.SETTINGS:
        return <SettingsScreen 
          {...commonProps}
          onUpdateSettings={setSettings} 
          onBack={() => setCurrentScreen(AppScreen.PROFILE)} 
          onSignOut={handleSignOut}
          onClearData={handleClearData}
          userProfile={userProfile}
        />;
      case AppScreen.STATS:
        return <StatsScreen {...commonProps} onBack={() => setCurrentScreen(AppScreen.DASHBOARD)} />;
      case AppScreen.PLANS:
        return <PlansScreen {...commonProps} currentPlan={activePlan} availablePlans={availablePlans} tdee={tdee} onSelectPlanId={setActivePlanId} />;
      default:
        return <Dashboard {...commonProps} history={mealHistory} profile={userProfile} onOpenProfile={() => setCurrentScreen(AppScreen.PROFILE)} targetKcal={2000} />;
    }
  };

  const showNavbar = [AppScreen.DASHBOARD, AppScreen.PROFILE, AppScreen.STATS, AppScreen.PLANS, AppScreen.SETTINGS].includes(currentScreen);

  return (
    <div className="h-screen w-full relative flex flex-col bg-background-dark overflow-hidden">
      <div className="flex-1 overflow-y-auto no-scrollbar relative">
        {renderScreen()}
      </div>
      {showNavbar && (
        <Navbar {...{t, settings}} activeScreen={currentScreen} onNavigate={setCurrentScreen} onScan={handleOpenCamera} />
      )}
    </div>
  );
};

export default App;

import React, { useRef, useMemo } from 'react';
import { UserProfile, Gender } from '../types';

interface ProfileScreenProps {
  profile: UserProfile;
  onUpdateProfile: (p: UserProfile) => void;
  onBack: () => void;
  onOpenSettings: () => void;
  tdee: number;
  t: any;
  settings: any;
}

const ProfileScreen: React.FC<ProfileScreenProps> = ({ profile, onUpdateProfile, onBack, onOpenSettings, tdee, t, settings }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const isMetric = settings.units === 'Metric';

  // Convert for display
  const displayWeight = useMemo(() => isMetric ? profile.weight : Math.round(profile.weight * 2.20462), [profile.weight, isMetric]);
  const displayHeight = useMemo(() => isMetric ? profile.height : Math.round(profile.height * 0.393701), [profile.height, isMetric]);

  const handleChange = (field: keyof UserProfile, value: any) => {
    let finalValue = value;
    // Convert back to metric if saved from imperial input
    if (field === 'weight' && !isMetric) finalValue = value / 2.20462;
    if (field === 'height' && !isMetric) finalValue = value / 0.393701;

    onUpdateProfile({ ...profile, [field]: finalValue });
  };

  const handleAvatarClick = () => fileInputRef.current?.click();

  return (
    <div className="bg-background-dark min-h-screen text-white pb-32 max-w-md mx-auto flex flex-col">
      <header className="flex items-center justify-between p-4 pt-6 sticky top-0 bg-background-dark/80 backdrop-blur-md z-10 border-b border-white/5">
        <div onClick={onBack} className="flex size-10 shrink-0 items-center justify-start cursor-pointer">
          <span className="material-symbols-outlined text-2xl">arrow_back_ios</span>
        </div>
        <h2 className="text-lg font-bold leading-tight tracking-tight flex-1 text-center">{t.profile}</h2>
        <button onClick={onOpenSettings} className="flex size-10 items-center justify-center rounded-full bg-white/5">
          <span className="material-symbols-outlined text-primary">settings</span>
        </button>
      </header>

      <section className="flex flex-col items-center px-4 py-6">
        <div className="relative mb-8">
          <div className="size-32 rounded-full border-4 border-primary/20 p-1">
            <div className="w-full h-full rounded-full bg-cover bg-center overflow-hidden bg-zinc-800" style={{ backgroundImage: `url("${profile.avatar}")` }} />
          </div>
          <button onClick={handleAvatarClick} className="absolute bottom-1 right-1 size-10 rounded-full bg-primary text-background-dark flex items-center justify-center shadow-lg border-4 border-background-dark">
            <span className="material-symbols-outlined text-xl font-bold">photo_camera</span>
          </button>
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={(e) => {
            const file = e.target.files?.[0];
            if (file) {
              const r = new FileReader();
              r.onload = (ev) => handleChange('avatar', ev.target?.result);
              r.readAsDataURL(file);
            }
          }} />
        </div>

        <div className="w-full space-y-6">
          <div className="bg-[#193322]/40 p-4 rounded-2xl border border-primary/20">
            <InputGroup label={t.nickname} value={profile.name} onChange={(v: any) => handleChange('name', v)} type="text" />
          </div>

          <div className="bg-[#1a2e20] p-6 rounded-2xl border border-white/5 w-full text-center">
            <p className="text-primary text-xs font-bold uppercase tracking-widest mb-1">{t.tdeeLabel}</p>
            <h1 className="text-5xl font-black text-white">{tdee}</h1>
            <p className="text-slate-400 text-sm mt-1">{t.dailyMaintenance}</p>
          </div>

          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <InputGroup label={`${t.weight} (${isMetric ? 'kg' : 'lbs'})`} value={displayWeight} onChange={(v: any) => handleChange('weight', Number(v))} type="number" />
              <InputGroup label={`${t.height} (${isMetric ? 'cm' : 'in'})`} value={displayHeight} onChange={(v: any) => handleChange('height', Number(v))} type="number" />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <InputGroup label={t.age} value={profile.age} onChange={(v: any) => handleChange('age', Number(v))} type="number" />
              <div className="flex flex-col gap-2">
                <p className="text-xs font-bold text-[#92c9a4] uppercase px-1">{t.gender}</p>
