const App: React.FC = () => {
  const [currentScreen, setCurrentScreen] = useState<AppScreen>(AppScreen.SPLASH);
  const [analysisResult, setAnalysisResult] = useState<MealAnalysis | null>(null);
  const [isViewingHistory, setIsViewingHistory] = useState(false);

  const [settings, setSettings] = useState({
    language: 'Chinese',
    units: 'Metric',
    notifications: true
  });

  const t = useMemo(() => translations[settings.language] || translations.English, [settings.language]);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Alex Rivera',
    avatar: 'https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?q=80&w=200&auto=format&fit=crop',
    weight: 78, 
    height: 175, 
    age: 28,
    gender: 'male',
    activityLevel: 1.2
  });

  const [activePlanId, setActivePlanId] = useState<string>('weight-loss');

  const availablePlans: MealPlan[] = [
    {
      id: 'weight-loss',
      title: 'Weight Loss',
      desc: 'Targeted calorie deficit for healthy fat loss.',
      kcalModifier: -500,
      proteinPct: 35,
      carbsPct: 35,
      fatsPct: 30,
      image: 'https://images.unsplash.com/photo-1490645935967-10de6ba17061?q=80&w=400&auto=format&fit=crop'
    },
    {
      id: 'muscle-building',
      title: 'Muscle Building',
      desc: 'High protein focus for lean muscle gains.',
      kcalModifier: 500,
      proteinPct: 40,
      carbsPct: 40,
      fatsPct: 20,
      image: 'https://images.unsplash.com/photo-1532384748853-8f54a8f476e2?q=80&w=400&auto=format&fit=crop'
    }
  ];

  const tdee = useMemo(() => {
    const { weight, height, age, gender, activityLevel } = userProfile;
    const bmr = gender === 'male'
      ? (10 * weight) + (6.25 * height) - (5 * age) + 5
      : (10 * weight) + (6.25 * height) - (5 * age) - 161;
    return Math.round(bmr * activityLevel);
  }, [userProfile]);

  const activePlan = useMemo(() => {
    const plan = availablePlans.find(p => p.id === activePlanId) || availablePlans[0];
    return {
      ...plan,
      dynamicKcal: tdee + plan.kcalModifier
    };
  }, [activePlanId, tdee]);

  // 修改：饮食历史初始化为空
  const [mealHistory, setMealHistory] = useState<MealHistoryItem[]>([]);

  const handleStart = () => setCurrentScreen(AppScreen.DASHBOARD);
  const handleOpenCamera = () => setCurrentScreen(AppScreen.CAMERA);

  const handleSignOut = () => setCurrentScreen(AppScreen.SPLASH);
  const handleClearData = () => setMealHistory([]);

  const handleMealClick = (meal: MealHistoryItem) => {
    setAnalysisResult(meal);
    setIsViewingHistory(true);
    setCurrentScreen(AppScreen.ANALYSIS);
  };

  const renderScreen = () => {
    const commonProps = { t, settings };
    switch (currentScreen) {
      case AppScreen.SPLASH:
        return <SplashScreen {...commonProps} onStart={handleStart} />;
      case AppScreen.DASHBOARD:
        return <Dashboard {...commonProps} history={mealHistory} profile={userProfile} onOpenProfile={() => setCurrentScreen(AppScreen.PROFILE)} targetKcal={activePlan.dynamicKcal || 2000} onSelectMeal={handleMealClick} />;
      case AppScreen.CAMERA:
        return <CameraScreen {...commonProps} onBack={() => setCurrentScreen(AppScreen.DASHBOARD)} onResult={(r) => { setAnalysisResult(r); setIsViewingHistory(false); setCurrentScreen(AppScreen.ANALYSIS); }} />;
      case AppScreen.ANALYSIS:
        return analysisResult ? (
          <AnalysisResults 
            {...commonProps} 
            result={analysisResult} 
            isViewOnly={isViewingHistory}
            onSave={(m) => {
              const newItem: MealHistoryItem = {
                ...m,
                id: Date.now().toString(),
                time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: false }),
                image: m.imageUrl || 'https://picsum.photos/200',
                status: 'VERIFIED'
              };
              setMealHistory(prev => [newItem, ...prev]);
              setCurrentScreen(AppScreen.DASHBOARD);
            }} 
            onBack={() => {
              if (isViewingHistory) {
                setCurrentScreen(AppScreen.DASHBOARD);
              } else {
                setCurrentScreen(AppScreen.CAMERA);
              }
            }} 
          />
        ) : null;
      case AppScreen.PROFILE:
        return <ProfileScreen 
          {...commonProps}
          profile={userProfile} 
          onUpdateProfile={setUserProfile} 
          onBack={() => setCurrentScreen(AppScreen.DASHBOARD)} 
          onOpenSettings={() => setCurrentScreen(AppScreen.SETTINGS)}
          tdee={tdee} 
        />;
      case AppScreen.SETTINGS:
        return <SettingsScreen 
          {...commonProps}
          onUpdateSettings={setSettings} 
          onBack={() => setCurrentScreen(AppScreen.PROFILE)} 
          onSignOut={handleSignOut}
          onClearData={handleClearData}
          userProfile={userProfile}
        />;
      case AppScreen.STATS:
        return <StatsScreen {...commonProps} onBack={() => setCurrentScreen(AppScreen.DASHBOARD)} />;
      case AppScreen.PLANS:
        return <PlansScreen {...commonProps} currentPlan={activePlan} availablePlans={availablePlans} tdee={tdee} onSelectPlanId={setActivePlanId} />;
      default:
        return <Dashboard {...commonProps} history={mealHistory} profile={userProfile} onOpenProfile={() => setCurrentScreen(AppScreen.PROFILE)} targetKcal={2000} onSelectMeal={handleMealClick} />;
    }
  };

  const showNavbar = [AppScreen.DASHBOARD, AppScreen.PROFILE, AppScreen.STATS, AppScreen.PLANS, AppScreen.SETTINGS].includes(currentScreen);

  return (
    <div className="h-screen w-full relative flex flex-col bg-background-dark overflow-hidden">
      <div className="flex-1 overflow-y-auto no-scrollbar relative">
        {renderScreen()}
      </div>
      {showNavbar && (
        <Navbar {...{t, settings}} activeScreen={currentScreen} onNavigate={setCurrentScreen} onScan={handleOpenCamera} />
      )}
    </div>
  );
};

export default App;

import React, { useMemo } from 'react';
import { MealHistoryItem, UserProfile } from '../types';

interface DashboardProps {
  history: MealHistoryItem[];
  profile: UserProfile;
  onOpenProfile: () => void;
  targetKcal: number;
  t: any;
  onSelectMeal: (meal: MealHistoryItem) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ history, profile, onOpenProfile, targetKcal, t, onSelectMeal }) => {
  const consumed = useMemo(() => history.reduce((acc, curr) => acc + curr.totalCalories, 0), [history]);
  const proteinTotal = useMemo(() => history.reduce((acc, curr) => acc + curr.protein, 0), [history]);
  const carbsTotal = useMemo(() => history.reduce((acc, curr) => acc + curr.carbs, 0), [history]);
  const fatTotal = useMemo(() => history.reduce((acc, curr) => acc + curr.fats, 0), [history]);

  const remaining = Math.max(0, targetKcal - consumed);
  const progressPercent = Math.min(100, (consumed / targetKcal) * 100);

  const firstName = profile.name.split(' ')[0] || 'User';

  return (
    <div className="bg-background-dark min-h-screen text-white pb-32">
      <header className="sticky top-0 z-30 ios-blur bg-background-dark/80 px-4 py-3 flex items-center justify-between border-b border-white/5">
        <div className="flex items-center gap-3">
          <div 
            onClick={onOpenProfile}
            className="size-10 rounded-full bg-center bg-cover border-2 border-primary/30 cursor-pointer overflow-hidden shadow-[0_0_10px_rgba(19,236,91,0.2)]" 
            style={{ backgroundImage: `url("${profile.avatar}")` }}
          ></div>
          <div onClick={onOpenProfile} className="cursor-pointer group">
            <p className="text-xs text-[#92c9a4] font-medium">Monday, June 12</p>
            <div className="flex items-center gap-1">
              <h2 className="text-white text-base font-bold leading-tight tracking-tight group-hover:text-primary transition-colors">
                {t.goodMorning}, {firstName}
              </h2>
              <span className="material-symbols-outlined text-[14px] text-primary/60 group-hover:text-primary">edit</span>
            </div>
          </div>
        </div>
        <div className="flex gap-2">
          <button className="flex size-10 items-center justify-center rounded-full bg-[#193322] text-white hover:bg-[#2a4d36] transition-colors">
            <span className="material-symbols-outlined text-[24px]">notifications</span>
          </button>
        </div>
      </header>

      <main>
        <section className="flex flex-col items-center justify-center p-6 mt-4">
          <div className="relative flex items-center justify-center">
            <div className="w-64 h-64 rounded-full flex items-center justify-center shadow-[0_0_30px_rgba(19,236,91,0.15)] relative overflow-hidden" 
                 style={{ 
                   background: `radial-gradient(closest-side, #102216 85%, transparent 86% 100%), conic-gradient(#13ec5b ${progressPercent}%, #326744 0)` 
                 }}>
              <div className="flex flex-col items-center text-center z-10">
                <span className="text-[#92c9a4] text-sm font-medium uppercase tracking-widest">{t.remaining}</span>
                <span className="text-white text-5xl font-extrabold my-1 tracking-tight">{remaining.toLocaleString()}</span>
                <span className="text-[#92c9a4] text-sm">{t.goal}: {targetKcal.toLocaleString()} kcal</span>
              </div>
            </div>
            <div className="absolute -bottom-2 -left-4 bg-[#193322] px-4 py-2 rounded-xl border border-[#326744]">
              <p className="text-xs text-[#92c9a4]">{t.consumed}</p>
              <p className="text-sm font-bold">{consumed} kcal</p>
            </div>
            <div className="absolute -bottom-2 -right-4 bg-[#193322] px-4 py-2 rounded-xl border border-[#326744]">
              <p className="text-xs text-[#92c9a4]">{t.status}</p>
              <p className="text-sm font-bold">{progressPercent > 100 ? t.limitExceeded : t.onTrack}</p>
            </div>
          </div>
        </section>

        <section className="px-4 py-6">
          <div className="flex gap-3 overflow-x-auto pb-2 no-scrollbar">
            <MacroCard title={t.protein} icon="fitness_center" value={`${Math.round(proteinTotal)}g`} goal="150g" progress={Math.min(100, (proteinTotal/150)*100)} />
            <MacroCard title={t.carbs} icon="grain" value={`${Math.round(carbsTotal)}g`} goal="200g" progress={Math.min(100, (carbsTotal/200)*100)} />
            <MacroCard title={t.fat} icon="water_drop" value={`${Math.round(fatTotal)}g`} goal="70g" progress={Math.min(100, (fatTotal/70)*100)} />
          </div>
        </section>

        <div className="flex items-center justify-between px-4 pt-4 pb-2">
          <h2 className="text-white text-xl font-bold tracking-tight">{t.recentMeals}</h2>
          <button className="text-primary text-sm font-semibold">{t.seeAll}</button>
        </div>

        <div className="flex flex-col gap-4 px-4">
          {history.length > 0 ? history.map((meal) => (
            <MealCard key={meal.id} meal={meal} onClick={() => onSelectMeal(meal)} />
          )) : (
            <div className="py-10 text-center text-slate-500 bg-[#193322]/30 rounded-2xl border border-dashed border-[#326744]/40">
              <span className="material-symbols-outlined text-4xl mb-2 opacity-20">restaurant</span>
              <p className="text-sm">{t.emptyHistory}</p>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

