    weight: 70,
    height: 170,
    age: 25,
    gender: 'male',
    activityLevel: 1.2
  });

  const handleChange = (field: keyof UserProfile, value: any) => {
    setProfile(prev => ({ ...prev, [field]: value }));
  };

  const isStep1Valid = profile.name.trim() !== '' && profile.age > 0;
  const isStep2Valid = profile.weight > 0 && profile.height > 0;

  const activityLevels = [
    { value: 1.2, label: t.sedentary, desc: t.sedentaryDesc, icon: 'self_care' },
    { value: 1.375, label: t.light, desc: t.lightDesc, icon: 'directions_walk' },
