// Storage Keys
const STORAGE_KEYS = {
  PROFILE: 'calorie_ai_profile',
  HISTORY: 'calorie_ai_history',
  SETTINGS: 'calorie_ai_settings',
  ACTIVE_PLAN: 'calorie_ai_active_plan'
};

const App: React.FC = () => {
  // Initial Hydration from LocalStorage
  const [currentScreen, setCurrentScreen] = useState<AppScreen>(AppScreen.SPLASH);
  const [analysisResult, setAnalysisResult] = useState<MealAnalysis | null>(null);
  const [isViewingHistory, setIsViewingHistory] = useState(false);

  const [settings, setSettings] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.SETTINGS);
    return saved ? JSON.parse(saved) : {
      language: 'English',
      units: 'Metric',
      notifications: true
    };
  });

  const [userProfile, setUserProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.PROFILE);
    return saved ? JSON.parse(saved) : {
      name: '',
      avatar: 'https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?q=80&w=200&auto=format&fit=crop',
      weight: 70, 
      height: 170, 
      age: 25,
      gender: 'male',
      activityLevel: 1.2
    };
  });

  const [mealHistory, setMealHistory] = useState<MealHistoryItem[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.HISTORY);
    return saved ? JSON.parse(saved) : [];
  });

  const [activePlanId, setActivePlanId] = useState<string>(() => {
    return localStorage.getItem(STORAGE_KEYS.ACTIVE_PLAN) || 'weight-loss';
  });

  // Effects to save data to LocalStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.SETTINGS, JSON.stringify(settings));
  }, [settings]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.PROFILE, JSON.stringify(userProfile));
  }, [userProfile]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.HISTORY, JSON.stringify(mealHistory));
  }, [mealHistory]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.ACTIVE_PLAN, activePlanId);
  }, [activePlanId]);

  // Check if onboarding is needed on first load
  useEffect(() => {
    if (userProfile.name) {
      // User has already set up their profile
      setCurrentScreen(AppScreen.DASHBOARD);
    }
  }, []);

  const t = useMemo(() => translations[settings.language] || translations.English, [settings.language]);

  const availablePlans: MealPlan[] = [
    {
      id: 'weight-loss',
      title: 'Weight Loss',
      desc: 'Targeted calorie deficit for healthy fat loss.',
      kcalModifier: -500,
      proteinPct: 35,
      carbsPct: 35,
      fatsPct: 30,
      image: 'https://images.unsplash.com/photo-1490645935967-10de6ba17061?q=80&w=400&auto=format&fit=crop'
    },
    {
      id: 'muscle-building',
      title: 'Muscle Building',
      desc: 'High protein focus for lean muscle gains.',
      kcalModifier: 500,
      proteinPct: 40,
      carbsPct: 40,
      fatsPct: 20,
      image: 'https://images.unsplash.com/photo-1532384748853-8f54a8f476e2?q=80&w=400&auto=format&fit=crop'
    }
  ];

  const tdee = useMemo(() => {
    const { weight, height, age, gender, activityLevel } = userProfile;
    if (!weight || !height || !age) return 2000;
    const bmr = gender === 'male'
      ? (10 * weight) + (6.25 * height) - (5 * age) + 5
      : (10 * weight) + (6.25 * height) - (5 * age) - 161;
    return Math.round(bmr * activityLevel);
  }, [userProfile]);

  const activePlan = useMemo(() => {
    const plan = availablePlans.find(p => p.id === activePlanId) || availablePlans[0];
    return {
      ...plan,
      dynamicKcal: tdee + plan.kcalModifier
    };
  }, [activePlanId, tdee]);

  const handleStart = () => {
    if (userProfile.name) {
      setCurrentScreen(AppScreen.DASHBOARD);
    } else {
      setCurrentScreen(AppScreen.ONBOARDING);
    }
  };

  const handleOnboardingComplete = (profile: UserProfile, planId: string) => {
    setUserProfile(profile);
    setActivePlanId(planId);
    setCurrentScreen(AppScreen.DASHBOARD);
  };

  const handleOpenCamera = () => setCurrentScreen(AppScreen.CAMERA);

  const handleSignOut = () => {
    localStorage.clear();
    setMealHistory([]);
    setUserProfile({
      name: '',
      avatar: 'https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?q=80&w=200&auto=format&fit=crop',
      weight: 70, 
      height: 170, 
      age: 25,
      gender: 'male',
      activityLevel: 1.2
    });
    setSettings({
      language: 'English',
      units: 'Metric',
      notifications: true
    });
    setCurrentScreen(AppScreen.SPLASH);
  };

  const handleClearData = () => {
    setMealHistory([]);
    localStorage.removeItem(STORAGE_KEYS.HISTORY);
  };

  const handleMealClick = (meal: MealHistoryItem) => {
    setAnalysisResult(meal);
    setIsViewingHistory(true);
    setCurrentScreen(AppScreen.ANALYSIS);
  };

  const renderScreen = () => {
    const commonProps = { t, settings };
    switch (currentScreen) {
      case AppScreen.SPLASH:
        return <SplashScreen {...commonProps} onStart={handleStart} />;
      case AppScreen.ONBOARDING:
        return (
          <OnboardingScreen 
            {...commonProps} 
            onComplete={handleOnboardingComplete} 
            onLanguageSelect={(lang) => setSettings(prev => ({ ...prev, language: lang }))}
          />
        );
      case AppScreen.DASHBOARD:
        return <Dashboard {...commonProps} history={mealHistory} profile={userProfile} onOpenProfile={() => setCurrentScreen(AppScreen.PROFILE)} targetKcal={activePlan.dynamicKcal || 2000} onSelectMeal={handleMealClick} />;
      case AppScreen.CAMERA:
        return <CameraScreen {...commonProps} onBack={() => setCurrentScreen(AppScreen.DASHBOARD)} onResult={(r) => { setAnalysisResult(r); setIsViewingHistory(false); setCurrentScreen(AppScreen.ANALYSIS); }} />;
      case AppScreen.ANALYSIS:
        return analysisResult ? (
          <AnalysisResults 
            {...commonProps} 
            result={analysisResult} 
            isViewOnly={isViewingHistory}
            onSave={(m) => {
              const newItem: MealHistoryItem = {
                ...m,
                id: Date.now().toString(),
                time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: false }),
                image: m.imageUrl || 'https://picsum.photos/200',
                status: 'VERIFIED'
              };
              setMealHistory(prev => [newItem, ...prev]);
              setCurrentScreen(AppScreen.DASHBOARD);
            }} 
            onBack={() => {
              if (isViewingHistory) {
                setCurrentScreen(AppScreen.DASHBOARD);
              } else {
                setCurrentScreen(AppScreen.CAMERA);
              }
            }} 
          />
        ) : null;
      case AppScreen.PROFILE:
        return <ProfileScreen 
          {...commonProps}
          profile={userProfile} 
          onUpdateProfile={setUserProfile} 
          onBack={() => setCurrentScreen(AppScreen.DASHBOARD)} 
          onOpenSettings={() => setCurrentScreen(AppScreen.SETTINGS)}
          tdee={tdee} 
        />;
      case AppScreen.SETTINGS:
        return <SettingsScreen 
          {...commonProps}
          onUpdateSettings={setSettings} 
          onBack={() => setCurrentScreen(AppScreen.PROFILE)} 
          onSignOut={handleSignOut}
          onClearData={handleClearData}
          userProfile={userProfile}
        />;
      case AppScreen.STATS:
        return <StatsScreen {...commonProps} history={mealHistory} onBack={() => setCurrentScreen(AppScreen.DASHBOARD)} />;
      case AppScreen.PLANS:
        return <PlansScreen {...commonProps} currentPlan={activePlan} availablePlans={availablePlans} tdee={tdee} onSelectPlanId={setActivePlanId} />;
      default:
        return <Dashboard {...commonProps} history={mealHistory} profile={userProfile} onOpenProfile={() => setCurrentScreen(AppScreen.PROFILE)} targetKcal={2000} onSelectMeal={handleMealClick} />;
    }
  };

  const showNavbar = [AppScreen.DASHBOARD, AppScreen.PROFILE, AppScreen.STATS, AppScreen.PLANS, AppScreen.SETTINGS].includes(currentScreen);

  return (
    <div className="h-screen w-full relative flex flex-col bg-background-dark overflow-hidden">
      <div className="flex-1 overflow-y-auto no-scrollbar relative">
        {renderScreen()}
      </div>
      {showNavbar && (
        <Navbar {...{t, settings}} activeScreen={currentScreen} onNavigate={setCurrentScreen} onScan={handleOpenCamera} />
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { MealAnalysis } from "../types";

export const analyzeFoodImage = async (base64Image: string): Promise<MealAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image,
            },
          },
          {
            text: "Analyze this food image. Identify the dish and its ingredients. Provide estimated calories, protein (g), carbs (g), and fats (g). If you are unsure or the image is unclear, provide your best guess based on visible patterns or common meals. Return the data in JSON format."
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING, description: "Name of the dish" },
            totalCalories: { type: Type.NUMBER },
            protein: { type: Type.NUMBER },
            carbs: { type: Type.NUMBER },
            fats: { type: Type.NUMBER },
            ingredients: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  serving: { type: Type.STRING },
                  calories: { type: Type.NUMBER },
                  match: { type: Type.NUMBER, description: "Confidence percentage (0-100)" }
                },
                required: ["name", "serving", "calories", "match"]
              }
            }
          },
          required: ["name", "totalCalories", "protein", "carbs", "fats", "ingredients"]
        }
      }
    });

    const analysis = JSON.parse(response.text || '{}') as MealAnalysis;
    return analysis;
  } catch (error) {
    console.error("Gemini API Error:", error);
    // Fallback object if the AI fails completely or safety filters block it
    return {
      name: "Unidentified Meal",
      totalCalories: 0,
      protein: 0,
      carbs: 0,
      fats: 0,
      ingredients: []
    };
  }
};

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { analyzeFoodImage } from '../services/geminiService';
import { MealAnalysis } from '../types';

interface CameraScreenProps {
  onBack: () => void;
  onResult: (result: MealAnalysis) => void;
  t: any;
}

const CameraScreen: React.FC<CameraScreenProps> = ({ onBack, onResult, t }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [stream, setStream] = useState<MediaStream | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [mode, setMode] = useState<'single' | 'multi'>('single');
  const [flashOn, setFlashOn] = useState(false);
  const [hasTorch, setHasTorch] = useState(false);

  const startCamera = useCallback(async () => {
    try {
      const constraints = {
        video: { 
          facingMode: 'environment',
          width: { ideal: 1920 },
          height: { ideal: 1080 }
        },
        audio: false
      };
      const newStream = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(newStream);

      if (videoRef.current) {
        videoRef.current.srcObject = newStream;
      }

      const track = newStream.getVideoTracks()[0];
      if (track) {
        const capabilities = track.getCapabilities() as any;
        if (capabilities.torch) {
          setHasTorch(true);
        }
      }
    } catch (err) {
      console.error("Error accessing camera:", err);
    }
  }, []);

  useEffect(() => {
    startCamera();
    return () => {
      stream?.getTracks().forEach(track => track.stop());
    };
  }, [startCamera]);

  const toggleFlash = async () => {
    if (!stream) return;
    const track = stream.getVideoTracks()[0];
    if (track) {
      try {
        const newFlashState = !flashOn;
        await track.applyConstraints({
          advanced: [{ torch: newFlashState }]
        } as any);
        setFlashOn(newFlashState);
      } catch (err) {
        console.error("Error toggling flash:", err);
      }
    }
  };

  const processImage = async (dataUrl: string) => {
    setIsAnalyzing(true);
    try {
      const base64Image = dataUrl.split(',')[1];
      const result = await analyzeFoodImage(base64Image);
      onResult({ ...result, imageUrl: dataUrl });
    } catch (err) {
      console.error("Analysis failed:", err);
      // Fallback to manual entry with a placeholder
      onResult({
        name: t.language === 'Chinese' ? "新餐食" : "New Meal",
        totalCalories: 0,
        protein: 0,
        carbs: 0,
        fats: 0,
        ingredients: [],
        imageUrl: dataUrl
      });
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleManualEntry = () => {
    onResult({
      name: t.language === 'Chinese' ? "手动输入" : "Manual Entry",
      totalCalories: 0,
      protein: 0,
      carbs: 0,
      fats: 0,
      ingredients: [],
      imageUrl: "https://images.unsplash.com/photo-1498837167922-ddd27525d352?q=80&w=400&auto=format&fit=crop"
    });
  };

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isAnalyzing) return;

    const context = canvasRef.current.getContext('2d');
    if (context) {
      canvasRef.current.width = videoRef.current.videoWidth;
      canvasRef.current.height = videoRef.current.videoHeight;
      context.drawImage(videoRef.current, 0, 0);

      const dataUrl = canvasRef.current.toDataURL('image/jpeg', 0.8);

      if (flashOn) {
        toggleFlash();
      }

      await processImage(dataUrl);
    }
  };

  const handleGalleryClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const dataUrl = event.target?.result as string;
      if (dataUrl) {
        await processImage(dataUrl);
      }
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="relative flex h-screen w-full flex-col overflow-hidden bg-black">
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        muted
        className="absolute inset-0 w-full h-full object-cover z-0"
      />
      <canvas ref={canvasRef} className="hidden" />
      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        accept="image/*" 
        onChange={handleFileChange} 
      />

      <div className="relative z-30 flex items-center p-4 pt-12 justify-between">
        <button 
          onClick={onBack}
          className="flex size-10 items-center justify-center rounded-full bg-black/40 backdrop-blur-md active:scale-90 transition-transform"
        >
          <span className="material-symbols-outlined text-white">close</span>
        </button>
        <div className="flex flex-col items-center">
          <h2 className="text-white text-sm font-bold leading-tight tracking-wider uppercase">AI {t.scanFood}</h2>
          <div className="flex items-center gap-1">
            <div className="size-2 rounded-full bg-primary animate-pulse"></div>
            <span className="text-xs text-white/80 font-medium">LIVE</span>
          </div>
        </div>
        <button 
          onClick={handleManualEntry}
          className="flex size-10 items-center justify-center rounded-full bg-black/40 backdrop-blur-md text-white hover:text-primary transition-colors"
        >
          <span className="material-symbols-outlined">edit_note</span>
        </button>
      </div>

      <div className="relative z-10 flex-1 flex items-center justify-center p-8">
        <div className="relative w-full aspect-square max-w-[320px]">
          <div className="absolute top-0 left-0 w-10 h-10 border-t-4 border-l-4 border-primary rounded-tl-xl"></div>
          <div className="absolute top-0 right-0 w-10 h-10 border-t-4 border-r-4 border-primary rounded-tr-xl"></div>
          <div className="absolute bottom-0 left-0 w-10 h-10 border-b-4 border-l-4 border-primary rounded-bl-xl"></div>
          <div className="absolute bottom-0 right-0 w-10 h-10 border-b-4 border-r-4 border-primary rounded-br-xl"></div>

          <div className="absolute top-[40%] left-0 w-full h-[2px] bg-gradient-to-r from-transparent via-primary to-transparent shadow-[0_0_15px_#13ec5b] animate-[bounce_2s_infinite]"></div>

          {isAnalyzing && (
            <div className="absolute inset-0 flex items-center justify-center bg-black/60 rounded-xl backdrop-blur-sm">
              <div className="flex flex-col items-center gap-3">
                <div className="w-10 h-10 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
                <span className="text-sm font-black text-primary tracking-widest uppercase">{t.analyzing}</span>
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="relative z-30 bg-gradient-to-t from-black/90 via-black/40 to-transparent pb-10 pt-6 px-4">
        <h4 className="text-white text-sm font-medium leading-normal tracking-wide text-center mb-4 opacity-90">
          {t.pointCamera}
        </h4>

        <div className="flex max-w-[280px] mx-auto mb-8">
          <div className="flex h-11 flex-1 items-center justify-center rounded-full bg-black/60 backdrop-blur-xl p-1 border border-white/10">
            <button 
              onClick={() => setMode('single')}
              className={`flex-1 h-full rounded-full text-xs font-bold transition-all ${mode === 'single' ? 'bg-primary text-black' : 'text-white/70'}`}
            >
              {t.language === 'Chinese' ? '单品' : 'Single'}
            </button>
            <button 
              onClick={() => setMode('multi')}
              className={`flex-1 h-full rounded-full text-xs font-bold transition-all ${mode === 'multi' ? 'bg-primary text-black' : 'text-white/70'}`}
            >
              {t.language === 'Chinese' ? '多品' : 'Multi'}
            </button>
          </div>
        </div>

        <div className="flex items-center justify-between max-w-xs mx-auto mb-4 px-4">
          <button 
            onClick={handleGalleryClick}
            className="flex shrink-0 items-center justify-center rounded-xl size-12 bg-white/10 backdrop-blur-md border border-white/20 overflow-hidden active:scale-90 transition-transform"
          >
            <span className="material-symbols-outlined text-white text-2xl">photo_library</span>
          </button>

          <div className="relative flex items-center justify-center">
            <div className={`absolute inset-0 rounded-full border-4 border-primary ${isAnalyzing ? 'animate-pulse' : 'animate-ping opacity-20'}`}></div>
            <button 
              onClick={captureAndAnalyze}
              disabled={isAnalyzing}
              className="relative flex shrink-0 items-center justify-center rounded-full size-20 bg-white p-1 shadow-[0_0_20px_rgba(255,255,255,0.3)] active:scale-90 transition-transform"
            >
              <div className="w-full h-full rounded-full border-4 border-black/10 flex items-center justify-center">
                {isAnalyzing ? (
                   <div className="size-8 bg-primary rounded-sm animate-pulse"></div>
                ) : (
                  <div className="size-16 rounded-full border-2 border-black/5 flex items-center justify-center bg-slate-50">
                    <div className="size-14 rounded-full bg-white shadow-inner"></div>
                  </div>
                )}
              </div>
            </button>
          </div>

          <button 
            onClick={toggleFlash}
            disabled={!hasTorch}
            className={`flex shrink-0 items-center justify-center rounded-full size-12 backdrop-blur-md border border-white/20 active:scale-90 transition-all ${flashOn ? 'bg-primary text-black' : 'bg-white/10 text-white'} ${!hasTorch ? 'opacity-30' : ''}`}
          >
            <span className="material-symbols-outlined text-2xl">{flashOn ? 'flash_off' : 'flash_on'}</span>
          </button>
        </div>
      </div>
    </div>
  );
};

