      console.error("Analysis failed:", err);
      onResult({
        name: t.language === 'Chinese' ? "识别失败" : "Recognition Failed",
        totalCalories: 0,
        protein: 0,
        carbs: 0,
        fats: 0,
        ingredients: [],
